<?php
/**
 * One-shot installer.
 *
 * Simply's file manager will create a new file but silently refuses to OVERWRITE
 * an existing one, and its delete button does not fire reliably. PHP has none of
 * those problems. So the new code travels inside this file, writes itself into
 * place, and then deletes itself.
 *
 * Run once:  /install-19bb1102.php?t=19bb1102a90f612302c7f9ab4fc43c2e
 * It removes itself on success — there is no lasting write endpoint.
 */

if (($_GET['t'] ?? '') !== '19bb1102a90f612302c7f9ab4fc43c2e') {
    http_response_code(404);
    exit('Not found');
}

$files = [
    'auth-lib.php' => '',
    'auth.php' => '',
    'approve.php' => '',
    'account-setup.php' => 'PD9waHAKLyogU3BlbnQgb25lLW9mZiBtYWludGVuYW5jZSBzY3JpcHQuIE5ldXRyYWxpc2VkIG9uIHB1cnBvc2U6IGl0IGNvdWxkIHJld3JpdGUKICAgdGhlIHVzZXIgc3RvcmUsIGFuZCBpdHMgZ3VhcmQgdG9rZW4gbGl2ZXMgaW4gYSBwdWJsaWMgcmVwby4gSXQgbm93IGRvZXMKICAgbm90aGluZy4gKi8KaHR0cF9yZXNwb25zZV9jb2RlKDQwNCk7CmV4aXQoJ05vdCBmb3VuZCcpOwo=',
    'set-password.php' => 'PD9waHAKLyogU3BlbnQgb25lLW9mZiBtYWludGVuYW5jZSBzY3JpcHQuIE5ldXRyYWxpc2VkIG9uIHB1cnBvc2U6IGl0IGNvdWxkIHJld3JpdGUKICAgdGhlIHVzZXIgc3RvcmUsIGFuZCBpdHMgZ3VhcmQgdG9rZW4gbGl2ZXMgaW4gYSBwdWJsaWMgcmVwby4gSXQgbm93IGRvZXMKICAgbm90aGluZy4gKi8KaHR0cF9yZXNwb25zZV9jb2RlKDQwNCk7CmV4aXQoJ05vdCBmb3VuZCcpOwo=',
    'fix-htaccess.php' => 'PD9waHAKLyogU3BlbnQgb25lLW9mZiBtYWludGVuYW5jZSBzY3JpcHQuIE5ldXRyYWxpc2VkIG9uIHB1cnBvc2U6IGl0IGNvdWxkIHJld3JpdGUKICAgdGhlIHVzZXIgc3RvcmUsIGFuZCBpdHMgZ3VhcmQgdG9rZW4gbGl2ZXMgaW4gYSBwdWJsaWMgcmVwby4gSXQgbm93IGRvZXMKICAgbm90aGluZy4gKi8KaHR0cF9yZXNwb25zZV9jb2RlKDQwNCk7CmV4aXQoJ05vdCBmb3VuZCcpOwo=',
];

header('Content-Type: text/plain; charset=utf-8');

$dir = __DIR__;
$ok  = true;

foreach ($files as $name => $b64) {
    $data = base64_decode($b64, true);
    if ($data === false) { echo "DECODE FAILED  $name\n"; $ok = false; continue; }

    $path = $dir . '/' . $name;
    $tmp  = $path . '.tmp';

    /* Keep a copy of whatever is being replaced — never overwrite without a way back. */
    if (is_file($path)) {
        @copy($path, $dir . '/lgc-data/backup-' . $name . '-' . date('Ymd-His') . '.txt');
    }

    if (@file_put_contents($tmp, $data, LOCK_EX) === false || !@rename($tmp, $path)) {
        echo "WRITE FAILED   $name\n";
        $ok = false;
        continue;
    }
    echo sprintf("wrote %-22s %6d bytes\n", $name, strlen($data));
}

/* The user store moves from PHP to JSON — start it clean, so everyone signs up. */
$store = $dir . '/lgc-data/users.json';
if (!is_file($store)) {
    @file_put_contents($store, "[]\n", LOCK_EX);
    echo "\ncreated lgc-data/users.json (empty — everyone signs up)\n";
}

echo $ok ? "\nOK — installed.\n" : "\nSOMETHING FAILED — read the lines above.\n";

/* Remove myself. A permanent code-writing endpoint is not something to leave lying around. */
if ($ok && @unlink(__FILE__)) {
    echo "This installer has deleted itself.\n";
} else {
    echo "NOTE: could not delete the installer — remove /install-19bb1102.php by hand.\n";
}
